section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/devops-lb-high-availability.json",
  "title": "Load Balancer High Availability and Cloud Patterns",
  "type": "object",
  "required": [
    "topology",
    "cloud_lb_product",
    "regions",
    "failover_rto_s",
    "game_day_cadence",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "topology": {
      "enum": [
        "active_passive_vrrp",
        "active_active",
        "anycast",
        "cloud_managed",
        "dns_failover"
      ]
    },
    "cloud_lb_product": {
      "enum": [
        "none",
        "aws_alb",
        "aws_nlb",
        "aws_glb",
        "gcp_https_lb",
        "gcp_tcp_lb",
        "azure_front_door",
        "azure_lb"
      ]
    },
    "regions": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "region",
          "azs"
        ]
      }
    },
    "failover_rto_s": {
      "type": "integer",
      "minimum": 1
    },
    "game_day_cadence": {
      "enum": [
        "quarterly",
        "biannual",
        "monthly"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
